  }, {}), "import sys

class Solution:
    def kthSmallest(self, matrix: List[List[int]], k: int) -int:
        rows = len(matrix)
        cols = len(matrix[0])
        cursors = [0] * rows
        cnt = 0
        ans = None
        while cnt < k:
            min_val = sys.maxsize
            min_row = None
            for i in range(0, rows):
                if cursors[i] >= cols:
                    continue
                if matrix[i][cursors[i]] < min_val:
                    min_val = matrix[i][cursors[i]]
                    min_row = i
            cursors[min_row] += 1
            ans = min_val
            cnt += 1
        return ans
