        for i, c in enumerate(s):
            if ord(c) >= ord('0'):  #【1】
                d = d * 10 - ord('0') + ord(c)  # 【2】
            if (c != ' ' and ord(c) < ord('0')) or i == len(s) - 1: #【3】
                if prev_sign == '+':
                    data.append(d)
                elif prev_sign == '-':
                    data.append(-d)
                elif prev_sign == '*':
                    prev = data.pop()
                    data.append(d * prev)
                elif prev_sign == '/':  #【4】
                    prev = data.pop()
                    if prev < 0:
                        data.append(-1 * ((-1 * prev) // d))
                    else:
                        data.append( prev // d)
                prev_sign = c
                d = 0
        res = 0
        for n in data:
            res += n
        return res
